@namespace sv_c5c3f0559b994cc39fbf67a04e97c82f.Components.Pages.Apply
@using sv_c5c3f0559b994cc39fbf67a04e97c82f.Models

<h4 class="mb-4">Review Your Application</h4>

@if (submitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">🎉 Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@applicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(0)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small class="text-muted">@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

