@rendermode InteractiveServer

@namespace sv_c5c3f0559b994cc39fbf67a04e97c82f.Components.Pages.Apply
@using sv_c5c3f0559b994cc39fbf67a04e97c82f.Models

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        ApplicationService="ApplicationService"
                        OnBack="PreviousStep"
                        OnEditSection="GoToStep" />
            break;
    }
</div>

@code {
    private int currentStep;
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, 4);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = Math.Clamp(step, 0, 4);
}
