@namespace sv_c5c3f0559b994cc39fbf67a04e97c82f.Components.Pages.Apply

<nav aria-label="Application steps" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (var i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;

            <li class="text-center flex-fill position-relative @(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")"
                role="button"
                @onclick="() => OnStepClick(step)"
                style="cursor: @(isCompleted ? "pointer" : "default")">
                <div class="rounded-circle d-inline-flex align-items-center justify-content-center mb-1
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light border")"
                     style="width: 2rem; height: 2rem; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <div class="small">@StepNames[step]</div>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepSelected { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

